module rnn_inference (  
    input clk,  
    input rst,  
    input [4:0] x,  
    output reg [4:0] state  
);  
    parameter weight = 5'b00011; // Weight multiplier (3)  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst)  
            state <= 5'b00000;  
        else  
            state <= (state * weight) + x;  
    end  
endmodule
